import React, { useEffect, useMemo, useState } from "react";
import CodeMirror from "@uiw/react-codemirror";
import { html as htmlLang } from "@codemirror/lang-html";
import { css as cssLang } from "@codemirror/lang-css";
import { javascript as jsLang } from "@codemirror/lang-javascript";
import "./App.css";

function App() {
  const [language, setLanguage] = useState("html");

  const [html, setHtml] = useState("<h1>Hello</h1>");
  const [css, setCss] = useState("h1{color:red}");
  const [js, setJs] = useState("console.log('Hello');");

  // Load
  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("project"));
    if (data) {
      setHtml(data.html || "");
      setCss(data.css || "");
      setJs(data.js || "");
    }
  }, []);

  // Save
  useEffect(() => {
    localStorage.setItem("project", JSON.stringify({ html, css, js }));
  }, [html, css, js]);

  // Copy Code
  const copyCode = () => {
    const code =
      language === "html"
        ? html
        : language === "css"
        ? css
        : js;

    navigator.clipboard.writeText(code);
    alert("Copied!");
  };

  // Download
  const downloadCode = () => {
    const file = new Blob(
      [html + "\n<style>" + css + "</style>\n<script>" + js + "</script>"],
      { type: "text/html" }
    );
    const a = document.createElement("a");
    a.href = URL.createObjectURL(file);
    a.download = "project.html";
    a.click();
  };

  const output = `
    <html>
      <style>${css}</style>
      <body>
        ${html}
        <script>${js}<\/script>
      </body>
    </html>
  `;

  // Editor language
  const getLang = () => {
    if (language === "html") return htmlLang();
    if (language === "css") return cssLang();
    return jsLang();
  };

  return (
    <div className="app">

      {/* TOP */}
      <div className="topbar">
        <h2>🔥 CodeSnip Pro</h2>

        <select onChange={(e) => setLanguage(e.target.value)}>
          <option value="html">HTML</option>
          <option value="css">CSS</option>
          <option value="js">JavaScript</option>
        </select>

        <button onClick={copyCode}>Copy</button>
        <button onClick={downloadCode}>Download</button>
      </div>

      {/* MAIN */}
      <div className="container">

        {/* EDITOR */}
        <div className="editor">
          <CodeMirror
            value={language === "html" ? html : language === "css" ? css : js}
            height="100%"
            extensions={[getLang()]}
            onChange={(value) => {
              if (language === "html") setHtml(value);
              if (language === "css") setCss(value);
              if (language === "js") setJs(value);
            }}
          />
        </div>

        {/* PREVIEW */}
        <div className="preview">
          <iframe srcDoc={output} title="preview" sandbox="allow-scripts" />
        </div>

      </div>
    </div>
  );
}

export default App;
